                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
// وظيفة فتح القائمة (يتم استدعاؤها عند اختيار منشأة)
function showPanel(place) {
    const panel = document.getElementById("side-panel");
    
    // 1. تعبئة البيانات في القائمة
    document.getElementById("display-name").innerText = place.name;
    // ... باقي البيانات

    // 2. إضافة كلاس 'open' لتفعيل حركة الانزلاق والظهور
    panel.classList.add("open");
}

// وظيفة إغلاق القائمة (يتم استدعاؤها عند الضغط على X)
function closePanel() {
    const panel = document.getElementById("side-panel");
    
    // إزالة كلاس 'open' لتعود القائمة وتختفي يمين الشاشة
    panel.classList.remove("open");
}

// تحديث مستمع البحث (Autocomplete)
autocomplete.addListener("place_changed", () => {
    const place = autocomplete.getPlace();
    if (!place.geometry) return;

    // تحريك الخريطة
    map.setCenter(place.geometry.location);
    map.setZoom(17);

    // استدعاء وظيفة فتح القائمة المنزلقة
    showPanel(place);
    
    // جلب التفاصيل الإضافية والتعليقات
    fetchFullDetails(place.place_id);
});
 </script>

